// Prepare context for AI personalization
const lead = $input.first().json;
const currentMonth = new Date().toLocaleString('default', { month: 'long' });
const currentSeason = (() => {
  const month = new Date().getMonth();
  if (month >= 2 && month <= 4) return 'spring';
  if (month >= 5 && month <= 7) return 'summer';
  if (month >= 8 && month <= 10) return 'fall';
  return 'winter';
})();

// Determine hook angle based on loss reason
const lossReason = (lead.fields['Loss Reason'] || '').toLowerCase();
let hookAngle = 'general';

if (lossReason.includes('price') || lossReason.includes('expensive') || lossReason.includes('cost')) {
  hookAngle = 'value_offer';
} else if (lossReason.includes('timing') || lossReason.includes('busy') || lossReason.includes('later')) {
  hookAngle = 'timing_check';
} else if (lossReason.includes('competitor') || lossReason.includes('another')) {
  hookAngle = 'service_quality';
} else if (lossReason.includes('not ready') || lossReason.includes('thinking')) {
  hookAngle = 'gentle_reminder';
}

return {
  json: {
    lead: lead,
    context: {
      firstName: lead.fields['First Name'] || 'there',
      lastName: lead.fields['Last Name'] || '',
      serviceNeeded: lead.fields['Service Needed'] || 'HVAC service',
      lossReason: lead.fields['Loss Reason'] || 'no reason provided',
      lastContact: lead.fields['Last Contact'],
      hookAngle: hookAngle,
      currentMonth: currentMonth,
      currentSeason: currentSeason,
      daysSinceContact: Math.floor((new Date() - new Date(lead.fields['Last Contact'])) / (1000 * 60 * 60 * 24))
    }
  }
};

