// Clean and validate the SMS
const rawSms = $input.first().json.message?.content || $input.first().json.text || '';
let cleanedSms = rawSms.trim();

// Remove any quotes that GPT might add
cleanedSms = cleanedSms.replace(/^"|"$/g, '');
cleanedSms = cleanedSms.replace(/^'|'$/g, '');

// Ensure under 160 chars (SMS limit)
if (cleanedSms.length > 160) {
  // Find last complete sentence under 155 chars
  const truncated = cleanedSms.substring(0, 155);
  const lastPeriod = truncated.lastIndexOf('.');
  const lastQuestion = truncated.lastIndexOf('?');
  const cutPoint = Math.max(lastPeriod, lastQuestion);

  if (cutPoint > 100) {
    cleanedSms = truncated.substring(0, cutPoint + 1);
  } else {
    cleanedSms = truncated + '...';
  }
}

const leadData = $('Prepare AI Context').first().json;

return {
  json: {
    smsContent: cleanedSms,
    charCount: cleanedSms.length,
    lead: leadData.lead,
    context: leadData.context
  }
};

// Summary of batch processing
const allItems = $('Loop Over Leads').all();

return {
  json: {
    batchComplete: true,
    leadsProcessed: allItems.length,
    timestamp: new Date().toISOString(),
    nextBatchIn: '24 hours'
  }
};
